	providerModelsCache.entries = make(map[string]providerModelsCacheEntry)
	providerModelsCache.inFlight = make(map[string]chan struct{})
	providerModelsCache.Unlock()
	t.Cleanup(func() {
		providerModelsCache.Lock()
		providerModelsCache.entries = make(map[string]providerModelsCacheEntry)
