184	// detectProviderOrHarness looks up a name against providers first, then
185	// harnesses, returning the resolved kind and quota signal (if any).
186	func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
187		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
188			harnesses, _ := svc.ListHarnesses(ctx)
189			for _, h := range harnesses {
190				if strings.EqualFold(h.Name, name) {
191					q := quotaFromHarnessInfo(h)
192					return ProviderKindHarness, detectedFromQuota(q)
193				}
194			}
195		}
196		if snapshots, ok, _ := agent.ConfiguredProviderSnapshots(r.workingDir(ctx)); ok {
197			for _, p := range snapshots {
198				if strings.EqualFold(p.Name, name) {
199					q := quotaFromProviderInfo(p)
200					return ProviderKindEndpoint, detectedFromQuota(q)
201				}
202			}
203		}
204		if providers, err := liveProviderInfos(ctx, r.workingDir(ctx)); err == nil {
205			for _, p := range providers {
206				if strings.EqualFold(p.Name, name) {
207					q := quotaFromProviderInfo(p)
208					return ProviderKindEndpoint, detectedFromQuota(q)
209				}
210			}
211		}
212		return ProviderKindEndpoint, nil
213	}
